class AuthenticatedApiClient {
  constructor(oauthService) {
    this.oauthService = oauthService;
    this.baseUrl = 'https://api.example.com';
  }

  async request(path, options = {}) {
    const accessToken = await this.oauthService.getValidAccessToken();
    if (!accessToken) {
      throw new Error('Not authenticated');
    }

    const response = await fetch(`${this.baseUrl}${path}`, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
      },
    });

    // Handle 401 — attempt one token refresh and retry
    if (response.status === 401) {
      try {
        await this.oauthService.refreshAccessToken();
        const newToken = await SecureTokenStorage.getAccessToken();
        return fetch(`${this.baseUrl}${path}`, {
          ...options,
          headers: {
            ...options.headers,
            Authorization: `Bearer ${newToken}`,
            'Content-Type': 'application/json',
          },
        });
      } catch {
        throw new Error('Session expired — please log in again');
      }
    }

    return response;
  }
}

// ============================================================
// Auth Context
// ============================================================
const AuthContext = createContext(null);

const oauthService = new OAuthService();
const apiClient = new AuthenticatedApiClient(oauthService);

export function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);

  useEffect(() => {
    checkExistingSession();
  }, []);

  async function checkExistingSession() {
    try {
      const token = await oauthService.getValidAccessToken();
      if (token) {
        await fetchUserProfile();
        setIsAuthenticated(true);
      }
    } catch {
      await SecureTokenStorage.clearTokens();
    } finally {
      setIsLoading(false);
    }
  }

  async function fetchUserProfile() {
    try {
      const response = await apiClient.request('/userinfo');
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (error) {
      console.error('Failed to fetch user profile:', error);
    }
  }

  async function login() {
    try {
      setIsLoading(true);

      const authUrl = await oauthService.buildAuthorizationUrl();

      // Use system browser for auth (more secure than embedded WebView)
      const result = await AuthSession.startAsync({
        authUrl,
        returnUrl: OAUTH_CONFIG.redirectUri,
      });

      if (result.type === 'success' && result.params?.code) {
        await oauthService.exchangeCodeForTokens(
          result.params.code,
          result.params.state
        );
        await fetchUserProfile();
        setIsAuthenticated(true);
      } else if (result.type === 'error') {
        Alert.alert(
          'Authentication Error',
          result.params?.error_description || 'Login failed. Please try again.'
        );
      }
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
    } finally {
      setIsLoading(false);
    }
  }

  async function logout() {
    try {
      setIsLoading(true);
      await oauthService.revokeTokens();
      setIsAuthenticated(false);
      setUser(null);
    } catch (error) {
      console.error('Logout error:', error);
      // Clear local state even if revocation fails
      await SecureTokenStorage.clearTokens();
      setIsAuthenticated(false);
      setUser(null);
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <AuthContext.Provider
      value={{
        isAuthenticated,
        isLoading,
        user,
        login,
        logout,
        apiClient,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

